    "category": "Angular",
    "categoryKey": "angular",
    "language": "angular",
    "code": "Lazy loading is a technique in Angular that allows you to load JavaScript components asynchronously when a specific route activated. With lazy loading our application does not need to load everything at once, we can improve initial loading time of an application by loading the components on demand. Implement like below.\nApp.module.ts (Provide below format in app module) (you can set your component name your own)\n\n  import { NgModule } from '@angular/core';\n  import { RouterModule, Routes } from '@angular/router';\n  // authgaurd is optional\n  const appRoutes: Routes = [\n      {path: 'dashboard', loadChildren: \"./dashboard/dashboard.module#DashboardModule\" }\n  ];\n  \n  @NgModule({\n    declarations: [YourComponent],\n    imports: [RouterModule.forRoot(appRoutes, {useHash: true})],\n  })\n  export class AppModule { }\n\ndashboard.ts\n\nimport { Component, OnInit } from '@angular/core';\n@Component({\n  selector: 'app-dashboard',\n  templateUrl: './dashboard.component.html',\n  styleUrls: ['./dashboard.component.css']\n})\nexport class DashboardComponent {}\n\ndashoboard.routes.module.ts\n\nimport { NgModule } from '@angular/core';\nimport { Routes, RouterModule } from '@angular/router';\nimport { DashboardComponent } from './dashboard.component';\nconst routes: Routes = [\n  {path: '', component: DashboardComponent}\n];\n@NgModule({\n  imports: [RouterModule.forChild(routes)],\n  exports: [RouterModule]\n})\nexport class dadhboardRoutingModule { }\n\ndashboard.module.ts\n\nimport { NgModule } from \"@angular/core\";\nimport { CommonModule } from \"@angular/common\";\nimport { dadhboardRoutingModule } from './rote.module';\nimport { DashboardComponent } from './dashboard.component';\n@NgModule({\n  imports: [CommonModule,dadhboardRoutingModule],\n  declarations: [DashboardComponent]\n})\nexport class DashboardModule {}",
